    setIsMenuOpen(false);
  }, [location]);

  if (variant === 'classic') {
    return <ClassicLayout>{children}</ClassicLayout>;
  }

  if (variant === 'modern') {
    return <ModernLayout isMenuOpen={isMenuOpen} setIsMenuOpen={setIsMenuOpen}>{children}</ModernLayout>;
  }

  // DEFAULT: Archive Layout (The New V3)
  return (
    <div className="min-h-screen flex bg-brand-almond text-brand-ink font-serif selection:bg-brand-safety selection:text-white">
