import React, { useEffect } from 'react';
import { HashRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import Layout from './components/Layout';
import ArchiveHomePage from './pages/ArchiveHomePage';
import ModernHomePage from './pages/ModernHomePage';
import GuidePage from './pages/GuidePage';
import CategoryPage from './pages/CategoryPage';
import SearchPage from './pages/SearchPage';
import LegacyHomePage from './pages/LegacyHomePage';

// Wrapper to handle scroll restoration manually
const ScrollToTop = () => {
  const { pathname } = useLocation();

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);

  return null;
};

const App: React.FC = () => {
  return (
    <Router>
      <ScrollToTop />
      <Routes>
        {/* V3: Archive (The New Default) */}
        <Route path="/" element={<Layout variant="archive"><ArchiveHomePage /></Layout>} />

        {/* V2: Modern (Redmagic/Digital Brutalist) */}
        <Route path="/v2" element={<Layout variant="modern"><ModernHomePage /></Layout>} />

        {/* V1: Classic (Standard Directory) */}
        <Route path="/classic" element={<Layout variant="classic"><LegacyHomePage /></Layout>} />

        {/* Inner Pages (Shared across variants for now, wrapped in Archive layout by default) */}
        {/* Ideally, we could pass a query param or context to toggle layout style on inner pages too */}
        <Route path="/guide/:id" element={<Layout variant="archive"><GuidePage /></Layout>} />
        <Route path="/category/:id" element={<Layout variant="archive"><CategoryPage /></Layout>} />
        <Route path="/search" element={<Layout variant="archive"><SearchPage /></Layout>} />

        <Route path="/about" element={
          <Layout variant="archive">
            <div className="max-w-4xl mx-auto px-6 py-24">
              <span className="font-mono text-brand-safety text-xs font-bold uppercase tracking-widest mb-4 block">About Us</span>
              <h1 className="text-5xl md:text-7xl font-serif font-black text-brand-ink mb-12 italic">Building the <br/> Citizen's Handbook.</h1>
              <div className="prose prose-lg text-brand-ink/80 font-serif">
                <p className="text-xl leading-relaxed mb-6">
                  Signpost is a citizen-driven initiative designed to demystify public services in Nigeria. 
                  Our mission is to provide accurate, up-to-date, and easy-to-understand guides for everyday processes.
                </p>
                <p>
                  We believe that information is a public right. By organizing the chaos of public bureaucracy, 
                  we empower millions of Nigerians to save time, avoid extortion, and get things done.
                </p>
              </div>
            </div>
          </Layout>
        } />
      </Routes>
    </Router>
  );
};

export default App;

