const NavLink: React.FC<{ to: string; label: string; icon: any; smallIcon?: boolean }> = ({ to, label, icon: Icon, smallIcon }) => {
  const location = useLocation();
  const isActive = location.pathname === to;

  return (
    <Link 
      to={to} 
      className={`flex items-center gap-3 px-3 py-2 rounded-md transition-all group ${
        isActive 
          ? 'bg-brand-zinc-100 text-brand-zinc-950 font-medium' 
          : 'text-brand-zinc-500 hover:bg-brand-zinc-50 hover:text-brand-zinc-900'
      }`}
    >
      <Icon size={smallIcon ? 14 : 18} className={`${isActive ? 'text-brand-zinc-950' : 'text-brand-zinc-400 group-hover:text-brand-zinc-600'}`} />
      <span className="text-sm">{label}</span>
      {isActive && <div className="ml-auto w-1.5 h-1.5 rounded-full bg-brand-lemon"></div>}
    </Link>
  );
};

