import React, { useMemo } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { useData } from '../context/DataContext';
import { Search, ArrowRight, Frown } from 'lucide-react';

const SearchPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const query = searchParams.get('q') || '';
  const { guides } = useData();

  const results = useMemo(() => {
    if (!query) return [];
    const lowerQuery = query.toLowerCase();
    return guides.filter(guide => 
      guide.title.toLowerCase().includes(lowerQuery) || 
      guide.summary.toLowerCase().includes(lowerQuery) ||
      guide.steps.some(step => step.title.toLowerCase().includes(lowerQuery))
    );
  }, [query, guides]);

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="max-w-3xl mx-auto">
        <h1 className="text-2xl font-bold text-slate-900 mb-2">Search Results</h1>
        <p className="text-slate-500 mb-8">Showing results for "<span className="font-semibold text-slate-900">{query}</span>"</p>

        {results.length > 0 ? (
          <div className="space-y-4">
            {results.map(guide => (
              <Link key={guide.id} to={`/guide/${guide.id}`} className="block group">
                <article className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 hover:border-brand-green transition-colors">
                  <h2 className="text-xl font-bold text-brand-green mb-2 group-hover:underline">{guide.title}</h2>
                  <p className="text-slate-600">{guide.summary}</p>
                  <div className="mt-4 flex items-center gap-4 text-sm text-slate-400">
                    <span>{guide.estimatedTime}</span>
                    <span>•</span>
                    <span>Last updated {guide.lastUpdated}</span>
                  </div>
                </article>
              </Link>
            ))}
          </div>
        ) : (
          <div className="text-center py-20 bg-white rounded-xl border border-dashed border-slate-300">
            <Frown className="mx-auto h-12 w-12 text-slate-300 mb-4" />
            <h3 className="text-lg font-medium text-slate-900">No guides found</h3>
            <p className="text-slate-500 mt-1">Try adjusting your search terms or browse by category.</p>
            <Link to="/" className="mt-6 inline-block text-brand-green font-medium hover:underline">
              Back to Home
            </Link>
          </div>
        )}
      </div>
    </div>
  );
};

