import React, { useMemo } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { useData } from '../context/DataContext';
import { Search, ArrowRight, Frown } from 'lucide-react';

const SearchPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const query = searchParams.get('q') || '';
  const { guides } = useData();

  const results = useMemo(() => {
    if (!query) return [];
    const lowerQuery = query.toLowerCase();
    return guides.filter(guide => 
      guide.title.toLowerCase().includes(lowerQuery) || 
      guide.summary.toLowerCase().includes(lowerQuery) ||
      guide.steps.some(step => step.title.toLowerCase().includes(lowerQuery))
    );
  }, [query, guides]);

  return (
    <div className="max-w-[800px] mx-auto px-6 py-12">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-black mb-2">Search</h1>
        {query && <p className="text-gray-500">Results for "{query}"</p>}
      </div>

      <div className="space-y-4">
        {results.length > 0 ? (
            results.map(guide => (
              <Link key={guide.id} to={`/guide/${guide.id}`} className="block group">
                <article className="bg-white p-6 rounded-2xl border border-black/5 hover:border-black/10 transition-all hover:shadow-sm">
                  <h2 className="text-xl font-bold text-black mb-2 group-hover:text-green-600 transition-colors">{guide.title}</h2>
